import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import CaseCard from '../components/CaseCard';
import LoadingSpinner from '../components/LoadingSpinner';
import { casesData, Case } from '../data/cases';

const Home: React.FC = () => {
  const navigate = useNavigate();
  const [cases, setCases] = useState<Case[]>([]);
  const [filteredCases, setFilteredCases] = useState<Case[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [isLoading, setIsLoading] = useState(true);

  // Имитация загрузки данных
  useEffect(() => {
    const timer = setTimeout(() => {
      setCases(casesData);
      setFilteredCases(casesData);
      setIsLoading(false);
    }, 800);

    return () => clearTimeout(timer);
  }, []);

  // Фильтрация при изменении категории
  useEffect(() => {
    if (selectedCategory === 'all') {
      setFilteredCases(cases);
    } else {
      setFilteredCases(cases.filter(c => c.category === selectedCategory));
    }
  }, [selectedCategory, cases]);

  const categories = [
    { key: 'all', label: 'Все' },
    { key: 'basic', label: 'Базовые' },
    { key: 'premium', label: 'Премиум' },
    { key: 'exclusive', label: 'Эксклюзив' },
    { key: 'game_specific', label: 'По играм' },
  ];

  if (isLoading) {
    return <LoadingSpinner />;
  }

  return (
    <>
      <h1>🎲 FazerCases</h1>

      {/* Панель фильтрации с анимацией */}
      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2 }}
        style={{
          display: 'flex',
          gap: '8px',
          marginBottom: '30px',
          flexWrap: 'wrap',
          justifyContent: 'center',
        }}
      >
        {categories.map(cat => (
          <motion.button
            key={cat.key}
            onClick={() => setSelectedCategory(cat.key)}
            whileHover={{ scale: 1.05, y: -2 }}
            whileTap={{ scale: 0.95 }}
            animate={{
              background: selectedCategory === cat.key
                ? 'linear-gradient(145deg, #ffd700, #ffb347)'
                : 'rgba(255,255,255,0.1)',
              boxShadow: selectedCategory === cat.key
                ? '0 0 20px #ffd700'
                : 'none',
            }}
            transition={{ type: 'spring', stiffness: 500, damping: 30 }}
            style={{
              color: selectedCategory === cat.key ? '#000' : '#fff',
              border: '1px solid rgba(255,215,0,0.3)',
              padding: '8px 20px',
              borderRadius: '30px',
              cursor: 'pointer',
              fontSize: '0.95rem',
              fontWeight: selectedCategory === cat.key ? 'bold' : 'normal',
              backdropFilter: 'blur(10px)',
            }}
          >
            {cat.label}
          </motion.button>
        ))}
      </motion.div>

      {/* Сетка кейсов */}
      <motion.div
        className="cases-grid"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ staggerChildren: 0.1 }}
      >
        <AnimatePresence mode="wait">
          {filteredCases.map(caseItem => (
            <motion.div
              key={caseItem.id}
              layout
              initial={{ opacity: 0, y: 50 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -50 }}
              transition={{ type: 'spring', stiffness: 300, damping: 25 }}
            >
              <CaseCard
                caseData={caseItem}
                onOpen={() => navigate(`/case/${caseItem.id}`)}
              />
            </motion.div>
          ))}
        </AnimatePresence>
      </motion.div>

      {/* Пустое состояние */}
      {filteredCases.length === 0 && (
        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          style={{ textAlign: 'center', marginTop: '50px', color: '#999' }}
        >
          Кейсов в этой категории пока нет
        </motion.p>
      )}
    </>
  );
};

export default Home;
